// ORCHESTRATOR INITIALIZATION
console.log('=== MASTER ORCHESTRATOR STARTING ===');
console.log('Medical Residency Scheduler v2.0');
console.log('Revolutionary 9-Phase Pipeline');
console.log('');

const executionId = new Date().toISOString();
const startTime = Date.now();

const orchestratorConfig = {
  executionId: executionId,
  startTime: startTime,
  pipeline: {
    totalPhases: 9,
    phasesEnabled: [0, 1, 2, 3, 4, 6, 7, 8, 9],
    phase5Eliminated: true
  },
  performance: {
    targetRuntime: 15, // minutes
    legacyRuntime: 53, // minutes
    targetReduction: '71.7%'
  },
  metadata: {
    organization: 'Medical Residency Program',
    system: 'n8n Workflow Automation',
    revolutionaryBackend: true,
    civilianFriendlyFrontend: true
  }
};

console.log('Configuration:');
console.log(`  Execution ID: ${executionId}`);
console.log(`  Phases to execute: ${orchestratorConfig.pipeline.phasesEnabled.join(', ')}`);
console.log(`  Phase 5 eliminated: ${orchestratorConfig.pipeline.phase5Eliminated}`);
console.log(`  Target runtime: ${orchestratorConfig.performance.targetRuntime} minutes`);
console.log('');

return [{
  json: {
    orchestrator: orchestratorConfig,
    status: 'initialized',
    nextPhase: 0,
    message: 'Master orchestrator initialized - starting Phase 0'
  }
}];

// PHASE 0 COMPLETION HANDLER
const orchestrator = $('Initialize Orchestrator').first().json.orchestrator;
const phase0Result = $input.first().json;

console.log('=== PHASE 0 COMPLETE ===');
console.log(`Absences loaded: ${phase0Result.summary?.total_absences || 0}`);
console.log(`Faculty absences: ${phase0Result.summary?.faculty_absences || 0}`);
console.log(`Resident absences: ${phase0Result.summary?.resident_absences || 0}`);
console.log('');

return [{
  json: {
    orchestrator: orchestrator,
    phase0: phase0Result,
    status: 'phase0_complete',
    nextPhase: 1,
    message: 'Phase 0 complete - starting Phase 1'
  }
}];

// PHASE 1 COMPLETION HANDLER
const orchestrator = $('Phase 0 Completion Handler').first().json.orchestrator;
const phase0 = $('Phase 0 Completion Handler').first().json.phase0;
const phase1Result = $input.first().json;

console.log('=== PHASE 1 COMPLETE ===');
console.log(`Smart pairings created: ${phase1Result.summary?.total_pairings || 0}`);
console.log(`Absence-aware: ${phase1Result.summary?.absence_aware || false}`);
console.log('');

return [{
  json: {
    orchestrator: orchestrator,
    phase0: phase0,
    phase1: phase1Result,
    status: 'phase1_complete',
    nextPhase: 2,
    message: 'Phase 1 complete - starting Phase 2'
  }
}];

// PHASE 2 COMPLETION HANDLER
const orchestrator = $('Phase 1 Completion Handler').first().json.orchestrator;
const phase0 = $('Phase 1 Completion Handler').first().json.phase0;
const phase1 = $('Phase 1 Completion Handler').first().json.phase1;
const phase2Result = $input.first().json;

console.log('=== PHASE 2 COMPLETE ===');
console.log(`Resident assignments: ${phase2Result.summary?.total_assignments || 0}`);
console.log(`Residents assigned: ${phase2Result.summary?.residents_assigned || 0}`);
console.log('');

return [{
  json: {
    orchestrator: orchestrator,
    phase0: phase0,
    phase1: phase1,
    phase2: phase2Result,
    status: 'phase2_complete',
    nextPhase: 3,
    message: 'Phase 2 complete - starting Phase 3'
  }
}];

// PHASE 3 COMPLETION HANDLER
const orchestrator = $('Phase 2 Completion Handler').first().json.orchestrator;
const phase0 = $('Phase 2 Completion Handler').first().json.phase0;
const phase1 = $('Phase 2 Completion Handler').first().json.phase1;
const phase2 = $('Phase 2 Completion Handler').first().json.phase2;
const phase3Result = $input.first().json;

console.log('=== PHASE 3 COMPLETE ===');
console.log(`Faculty assignments: ${phase3Result.summary?.facultyAssignments || 0}`);
console.log(`ACGME compliance: ${phase3Result.summary?.acgmeCompliance?.complianceRate || 'N/A'}`);
console.log(`Absence substitutions: ${phase3Result.summary?.absenceSubstitutions || 0}`);
console.log('');

return [{
  json: {
    orchestrator: orchestrator,
    phase0: phase0,
    phase1: phase1,
    phase2: phase2,
    phase3: phase3Result,
    status: 'phase3_complete',
    nextPhase: 4,
    message: 'Phase 3 complete - starting Phase 4'
  }
}];

// PHASE 4 COMPLETION HANDLER
const orchestrator = $('Phase 3 Completion Handler').first().json.orchestrator;
const phase0 = $('Phase 3 Completion Handler').first().json.phase0;
const phase1 = $('Phase 3 Completion Handler').first().json.phase1;
const phase2 = $('Phase 3 Completion Handler').first().json.phase2;
const phase3 = $('Phase 3 Completion Handler').first().json.phase3;
const phase4Result = $input.first().json;

console.log('=== PHASE 4 COMPLETE ===');
console.log(`Call assignments: ${phase4Result.summary?.totalCallAssignments || 0}`);
console.log(`Equitable distribution: ${phase4Result.summary?.equitableDistribution || false}`);
console.log('');
console.log('NOTE: Phase 5 ELIMINATED - Revolutionary absence-aware processing!');
console.log('');

return [{
  json: {
    orchestrator: orchestrator,
    phase0: phase0,
    phase1: phase1,
    phase2: phase2,
    phase3: phase3,
    phase4: phase4Result,
    status: 'phase4_complete',
    nextPhase: 6,
    message: 'Phase 4 complete - Phase 5 SKIPPED (eliminated) - starting Phase 6'
  }
}];

// PHASE 6 COMPLETION HANDLER
const orchestrator = $('Phase 4 Completion Handler').first().json.orchestrator;
const phase0 = $('Phase 4 Completion Handler').first().json.phase0;
const phase1 = $('Phase 4 Completion Handler').first().json.phase1;
const phase2 = $('Phase 4 Completion Handler').first().json.phase2;
const phase3 = $('Phase 4 Completion Handler').first().json.phase3;
const phase4 = $('Phase 4 Completion Handler').first().json.phase4;
const phase6Result = $input.first().json;

console.log('=== PHASE 6 COMPLETE ===');
console.log(`Duplicates removed: ${phase6Result.cleanup_results?.duplicates_removed || 0}`);
console.log(`Conflicts resolved: ${phase6Result.cleanup_results?.conflicts_resolved || 0}`);
console.log(`Cleanup time: ${phase6Result.summary?.cleanup_time || 'N/A'}`);
console.log('');

return [{
  json: {
    orchestrator: orchestrator,
    phase0: phase0,
    phase1: phase1,
    phase2: phase2,
    phase3: phase3,
    phase4: phase4,
    phase6: phase6Result,
    status: 'phase6_complete',
    nextPhase: 7,
    message: 'Phase 6 complete - starting Phase 7'
  }
}];

// PHASE 7 COMPLETION HANDLER
const orchestrator = $('Phase 6 Completion Handler').first().json.orchestrator;
const phase0 = $('Phase 6 Completion Handler').first().json.phase0;
const phase1 = $('Phase 6 Completion Handler').first().json.phase1;
const phase2 = $('Phase 6 Completion Handler').first().json.phase2;
const phase3 = $('Phase 6 Completion Handler').first().json.phase3;
const phase4 = $('Phase 6 Completion Handler').first().json.phase4;
const phase6 = $('Phase 6 Completion Handler').first().json.phase6;
const phase7Result = $input.first().json;

console.log('=== PHASE 7 COMPLETE ===');
console.log(`Validation score: ${phase7Result.final_score || 0}/100`);
console.log(`ACGME compliant: ${phase7Result.acgme_validation?.duty_hours_compliant || false}`);
console.log(`Coverage gaps: ${phase7Result.acgme_validation?.coverage_gaps || 0}`);
console.log('');

return [{
  json: {
    orchestrator: orchestrator,
    phase0: phase0,
    phase1: phase1,
    phase2: phase2,
    phase3: phase3,
    phase4: phase4,
    phase6: phase6,
    phase7: phase7Result,
    status: 'phase7_complete',
    nextPhase: 9,
    message: 'Phase 7 complete - Phase 8 (Emergency Coverage) optional - starting Phase 9'
  }
}];

// FINAL COMPLETION HANDLER
const orchestrator = $('Phase 7 Completion Handler').first().json.orchestrator;
const phase0 = $('Phase 7 Completion Handler').first().json.phase0;
const phase1 = $('Phase 7 Completion Handler').first().json.phase1;
const phase2 = $('Phase 7 Completion Handler').first().json.phase2;
const phase3 = $('Phase 7 Completion Handler').first().json.phase3;
const phase4 = $('Phase 7 Completion Handler').first().json.phase4;
const phase6 = $('Phase 7 Completion Handler').first().json.phase6;
const phase7 = $('Phase 7 Completion Handler').first().json.phase7;
const phase9Result = $input.first().json;

const endTime = Date.now();
const totalRuntime = Math.round((endTime - orchestrator.startTime) / 1000 / 60); // minutes

console.log('=== PHASE 9 COMPLETE ===');
console.log(`Excel sheets: ${phase9Result.excel_workbook?.sheets?.length || 0}`);
console.log(`Format preserved: ${phase9Result.excel_workbook?.format_preserved || false}`);
console.log('');
console.log('=' .repeat(80));
console.log('=== MASTER ORCHESTRATOR COMPLETE ===');
console.log('=' .repeat(80));
console.log('');
console.log('EXECUTION SUMMARY:');
console.log(`  Execution ID: ${orchestrator.executionId}`);
console.log(`  Total runtime: ${totalRuntime} minutes`);
console.log(`  Target runtime: ${orchestrator.performance.targetRuntime} minutes`);
console.log(`  Legacy runtime: ${orchestrator.performance.legacyRuntime} minutes`);
console.log(`  Efficiency gain: ${orchestrator.performance.targetReduction}`);
console.log('');
console.log('PHASES EXECUTED:');
console.log(`  ✓ Phase 0: Absence Loading - ${phase0.summary?.total_absences || 0} absences`);
console.log(`  ✓ Phase 1: Smart Pairing - ${phase1.summary?.total_pairings || 0} pairings`);
console.log(`  ✓ Phase 2: Resident Association - ${phase2.summary?.total_assignments || 0} assignments`);
console.log(`  ✓ Phase 3: Faculty Assignment - ${phase3.summary?.facultyAssignments || 0} assignments`);
console.log(`  ✓ Phase 4: Call Scheduling - ${phase4.summary?.totalCallAssignments || 0} calls`);
console.log(`  ✗ Phase 5: ELIMINATED (Revolutionary improvement!)`);
console.log(`  ✓ Phase 6: Cleanup - ${phase6.cleanup_results?.duplicates_removed || 0} duplicates`);
console.log(`  ✓ Phase 7: Validation - ${phase7.final_score || 0}/100 score`);
console.log(`  ⊙ Phase 8: Emergency Coverage - Skipped (on-demand only)`);
console.log(`  ✓ Phase 9: Excel Export - ${phase9Result.excel_workbook?.sheets?.length || 0} sheets`);
console.log('');
console.log('PERFORMANCE:');
console.log(`  Runtime: ${totalRuntime} min vs ${orchestrator.performance.legacyRuntime} min legacy`);
const actualSavings = ((orchestrator.performance.legacyRuntime - totalRuntime) / orchestrator.performance.legacyRuntime * 100).toFixed(1);
console.log(`  Actual savings: ${actualSavings}%`);
console.log('');
console.log('ACGME COMPLIANCE:');
console.log(`  Validation score: ${phase7.final_score || 0}/100`);
console.log(`  Duty hours compliant: ${phase7.acgme_validation?.duty_hours_compliant || false}`);
console.log(`  Coverage gaps: ${phase7.acgme_validation?.coverage_gaps || 0}`);
console.log('');
console.log('✅ ALL PHASES COMPLETE - SCHEDULING PIPELINE SUCCESS!');
console.log('');

return [{
  json: {
    orchestrator_execution: {
      executionId: orchestrator.executionId,
      status: 'COMPLETE',
      totalRuntime: totalRuntime,
      targetRuntime: orchestrator.performance.targetRuntime,
      actualSavings: actualSavings + '%',
      phasesExecuted: [0, 1, 2, 3, 4, 6, 7, 9],
      phase5Eliminated: true
    },
    phase_results: {
      phase0: phase0,
      phase1: phase1,
      phase2: phase2,
      phase3: phase3,
      phase4: phase4,
      phase6: phase6,
      phase7: phase7,
      phase9: phase9Result
    },
    final_outputs: {
      excel_workbook: phase9Result.excel_workbook,
      validation_score: phase7.final_score,
      acgme_compliant: phase7.acgme_validation?.duty_hours_compliant,
      total_absences_processed: phase0.summary?.total_absences,
      total_assignments_created: (
        (phase2.summary?.total_assignments || 0) +
        (phase3.summary?.facultyAssignments || 0) +
        (phase4.summary?.totalCallAssignments || 0)
      )
    },
    success: true,
    message: 'Master orchestrator execution complete - all phases succeeded',
    timestamp: new Date().toISOString()
  }
}];
